// OpenCL kernel for mixbench benchmark - translated from OpenMP CPU version

#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
typedef short cl_half2[2];
#endif

#ifndef class_T
#define class_T float
#endif

#ifndef blockdim
#define blockdim 256
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 1
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 8
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 4
#endif

#ifdef BLOCK_STRIDED
#define STRIDE blockdim
#else
#define STRIDE 1
#endif

__attribute__((noinline))
class_T compute_iterations_loop(class_T value, class_T f) {
    class_T t = value;
    for (int j = 0; j < COMPUTE_ITERATIONS; j++) {
        t = t * t + f;
    }
    return t;
}

__kernel void benchmark_func(class_T seed, __global class_T* data) {
    size_t wi_idx = get_global_id(0);
    size_t total_wi = get_global_size(0);

    size_t base_idx = wi_idx * ELEMENTS_PER_THREAD * FUSION_DEGREE;
    size_t stride = total_wi * ELEMENTS_PER_THREAD * FUSION_DEGREE * STRIDE;

    class_T f = seed;

    for (size_t fusion = 0; fusion < FUSION_DEGREE; fusion++) {
        for (size_t elem = 0; elem < ELEMENTS_PER_THREAD; elem++) {
            size_t idx = base_idx + fusion * ELEMENTS_PER_THREAD + elem;

            for (size_t offset = 0; offset < stride; offset += stride) {
                size_t current_idx = idx + offset;
                class_T t = data[current_idx];

                for (int j = 0; j < COMPUTE_ITERATIONS; j++) {
                    t = t * t + f;
                }

                data[current_idx] = t;
            }
        }
    }
}

__kernel void benchmark_func_warmup(short seed, __global class_T* data) {
    size_t idx = get_global_id(0);
    size_t total = get_global_size(0);

    class_T f = (class_T)seed;
    class_T t = data[idx];

    for (int j = 0; j < 1; j++) {
        t = t * t + f;
    }

    data[idx] = t;
}
